import { expect, test, describe } from "vitest";
import { PleromaticAsciiBridge } from "../pleromatic-ascii-bridge";
import { MCKAY_CHI1 } from "../pleromatic-monster-mesh";

describe("Pleromatic ASCII Bridge — Direct Projection", () => {
  test("projectSubstrate maps Bule heartbeat to ASCII ramp", () => {
    const s = { level: 270, noiseEntropy: 50, buleyWeight: MCKAY_CHI1 };
    const ramp = " .@"; // Simple ramp
    
    const node = PleromaticAsciiBridge.projectSubstrate(s, ramp);
    
    // chi1 should map toward the end of the ramp (the signal)
    expect(node.char).toBe("@");
    expect(node.substrate.level).toBe(10); // Should be grounded
  });

  test("resonateFrame prunes high-entropy noise glyphs", () => {
    const chars = ["@", "@"];
    const lumas = [0.1, 0.9]; // High luma = high entropy
    const weights = [1, 5]; // High weight (5) > chi1 (1)
    
    const result = PleromaticAsciiBridge.resonateFrame(chars, lumas, weights);
    
    // First glyph: valid signal (low luma/entropy) -> kept
    expect(result.chars[0]).toBe("@");
    expect(result.lumas[0]).toBe(0.1);
    
    // Second glyph: high cost + high entropy -> collapsed by Binet Loop
    expect(result.chars[1]).toBe(".");
    expect(result.lumas[1]).toBeLessThan(0.9);
  });
});
